var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"於是你決定了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"와아, 언제 봐도 으리으리한 방이네.","JPN":"すごい……いつ見てもデカい部屋だね。","ENG":"Wow, this fancy room never fails to impress me.","TWN":"哇啊，不管什麼時候看，這裡都是個氣派莊嚴的房間呢。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"천장 높고, 환기도 잘 되는 거 같고......","JPN":"天井が高いし、風通しも良くて……","ENG":"It's got that high ceiling, and nice ventilation too...","TWN":"高高的天花板，通風好像也不錯……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"이런 곳에서 살려면 원룸이라도 월세가 엄청 비싸겠지?","JPN":"こんなところに住もうとすると、ワンルームでも相当家賃が高いだろうね。","ENG":"I bet it'll cost a fortune to live in a cushy place like this, huh?","TWN":"建在這樣的地段，即使是套房，月租肯定也很貴吧？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"......앗! 내 정신 좀 봐. 그러고 보니 난 무슨 일로 불렀어?","JPN":"……あっ！こうしてる場合じゃない。そういえば、何で私を呼んだの？","ENG":"Oh! Where are my manners. So what did you need to see me for anyway?","TWN":"……啊！看看我這腦袋，話說回來，你找我有什麼事嗎？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"어? 평생고용보장?","JPN":"え？終身契約？","ENG":"Huh? Lifetime job security?","TWN":"什麼？終身雇傭保證？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"나야 좋긴 한데, 정말 괜찮겠어?","JPN":"私はいいけど、本当にいいの？","ENG":"Sure, I'd love that. But are you sure?","TWN":"我當然是好了，不過真的沒關係嗎？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"아니, 아니! 내가 싫다는 건 절대로 아니고...... 으음......","JPN":"い、いや！　私が嫌なわけじゃなくて……うーん……","ENG":"Oh, no, no... I'm not saying that I don't like the idea at all! Hmm....","TWN":"沒有，沒有！絕對不是不喜歡啦……呃嗯……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"요즘 불경기에 고용불안이다 뭐다 얘기가 많잖아.","JPN":"最近、不景気で雇用不安やらいろいろ話題になってるからさ。","ENG":"It's just that, there's all that talk about the economy and unstable job security.","TWN":"因為最近不景氣，有很多人失業不是嗎？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"이렇게 나 혼자만 이런 혜택을 받아도 괜찮나 싶어서 말이지.","JPN":"こうして私だけいい思いしてもいいのかなって。","ENG":"I was just wondering if I really deserve all this when everyone's going through a rough time.","TWN":"就我一個人享有這樣的好處，真的沒關係吧？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"하하......","JPN":"はは……","ENG":"Hah hah...","TWN":"哈哈……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"난 말이지.","JPN":"私はね。","ENG":"You see...","TWN":"我啊。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"언니가 쓰러진 뒤로, 줄곧 혼자서만 싸워왔어.","JPN":"姉さんが倒れてから、ずっと一人で戦ってきた。","ENG":"I've always been fighting on my own ever since my sister collapsed.","TWN":"自從姐姐倒下後，我就一直是一個人戰鬥。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"언니가 깨어나지 못하면 영영 혼자가 될까 겁이 나서,","JPN":"姉さんがこのまま目が覚めなくて、ひとりぼっちになるのが怖くて、","ENG":"I was scared that I'd be all alone if she never wakes up.","TWN":"我害怕要是姐姐沒辦法醒來，我就永遠變成一個人了，"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};